export const messengerSource = "import * as React from 'react';\nimport { ChatBox } from '@mui/x-chat';\nimport type { ChatConversation, ChatMessage } from '@mui/x-chat/headless';\n\nconst adapter = {\n  async sendMessage() {\n    return new ReadableStream();\n  },\n};\n\nconst conversations: ChatConversation[] = [\n  {\n    id: 'release',\n    title: 'Release',\n    subtitle: 'Ship checklist',\n    unreadCount: 2,\n    readState: 'unread',\n  },\n  {\n    id: 'support',\n    title: 'Support',\n    subtitle: 'Follow up with Erin',\n    readState: 'read',\n  },\n];\n\nconst initialThreads: Record<string, ChatMessage[]> = {\n  release: [\n    {\n      id: 'release-1',\n      conversationId: 'release',\n      role: 'assistant',\n      author: { id: 'maya', displayName: 'Maya' },\n      parts: [{ type: 'text', text: 'Can you review the launch copy before 4 PM?' }],\n    },\n  ],\n  support: [\n    {\n      id: 'support-1',\n      conversationId: 'support',\n      role: 'user',\n      author: { id: 'you', displayName: 'You' },\n      parts: [{ type: 'text', text: 'I will send the updated reply this afternoon.' }],\n    },\n  ],\n};\n\nexport default function App() {\n  const [activeConversationId, setActiveConversationId] = React.useState(conversations[0].id);\n  const [messagesByConversation, setMessagesByConversation] = React.useState(initialThreads);\n\n  return (\n    <ChatBox\n      adapter={adapter}\n      conversations={conversations}\n      activeConversationId={activeConversationId}\n      messages={messagesByConversation[activeConversationId] ?? []}\n      features={{ conversationList: true }}\n      onActiveConversationChange={(nextId) => {\n        if (nextId) {\n          setActiveConversationId(nextId);\n        }\n      }}\n      onMessagesChange={(nextMessages) => {\n        setMessagesByConversation((prev) => ({\n          ...prev,\n          [activeConversationId]: nextMessages,\n        }));\n      }}\n    />\n  );\n}\n";

// Source: src/modules/components/overview/chat/mainDemo/code/agent/App.tsx
export const agentSource = "import { ChatBox } from '@mui/x-chat';\nimport type { ChatAdapter, ChatConversation, ChatMessageChunk } from '@mui/x-chat/headless';\n\nconst tasks: ChatConversation[] = [\n  {\n    id: 'fix-tests',\n    title: 'Fix failing tests',\n    subtitle: 'Awaiting approval',\n    unreadCount: 1,\n    readState: 'unread',\n  },\n];\n\nconst adapter: ChatAdapter = {\n  async sendMessage() {\n    return new ReadableStream<ChatMessageChunk>({\n      start(controller) {\n        controller.enqueue({\n          type: 'start',\n          messageId: 'assistant-1',\n          author: { id: 'codex', displayName: 'Codex' },\n        });\n        controller.enqueue({ type: 'start-step' });\n        controller.enqueue({ type: 'reasoning-start', id: 'reasoning-1' });\n        controller.enqueue({\n          type: 'reasoning-delta',\n          id: 'reasoning-1',\n          delta: 'I should inspect the failing test output before editing files.',\n        });\n        controller.enqueue({ type: 'reasoning-end', id: 'reasoning-1' });\n        controller.enqueue({\n          type: 'tool-approval-request',\n          dynamic: true,\n          toolCallId: 'bash-1',\n          toolName: 'bash',\n          input: { command: 'pnpm test --runInBand' },\n        });\n        controller.enqueue({ type: 'text-start', id: 'text-1' });\n        controller.enqueue({\n          type: 'text-delta',\n          id: 'text-1',\n          delta: 'I found the failing suite and I am ready to patch the import path.',\n        });\n        controller.enqueue({ type: 'text-end', id: 'text-1' });\n        controller.enqueue({ type: 'finish-step' });\n        controller.enqueue({ type: 'finish', messageId: 'assistant-1' });\n        controller.close();\n      },\n    });\n  },\n  async addToolApprovalResponse({ approved }) {\n    if (!approved) {\n      return;\n    }\n  },\n};\n\nexport default function App() {\n  return (\n    <ChatBox\n      adapter={adapter}\n      initialConversations={tasks}\n      initialActiveConversationId={tasks[0].id}\n    />\n  );\n}\n";

// Source: src/modules/components/overview/chat/mainDemo/code/widget/App.tsx
export const widgetSource = "import * as React from 'react';\nimport { ChatBox } from '@mui/x-chat';\nimport type { ChatConversation, ChatMessage } from '@mui/x-chat/headless';\n\nconst adapter = {\n  async sendMessage() {\n    return new ReadableStream();\n  },\n};\n\nconst conversations: ChatConversation[] = [\n  {\n    id: 'support',\n    title: 'Fin',\n    subtitle: 'Usually replies in a minute',\n  },\n];\n\nconst initialMessages: ChatMessage[] = [\n  {\n    id: 'support-1',\n    conversationId: 'support',\n    role: 'assistant',\n    author: { id: 'fin', displayName: 'Fin' },\n    parts: [{ type: 'text', text: 'What can I help you with today?' }],\n  },\n];\n\nexport default function App() {\n  const [activeConversationId, setActiveConversationId] = React.useState<string | undefined>(\n    undefined,\n  );\n  const [messages, setMessages] = React.useState(initialMessages);\n\n  return (\n    <ChatBox\n      adapter={adapter}\n      conversations={conversations}\n      activeConversationId={activeConversationId}\n      messages={activeConversationId ? messages : []}\n      onActiveConversationChange={(nextId) => setActiveConversationId(nextId ?? undefined)}\n      onMessagesChange={setMessages}\n      layoutMode=\"split\"\n      features={{ conversationList: true }}\n    />\n  );\n}\n";

// Source: src/modules/components/overview/chat/mainDemo/code/captions/App.tsx
export const captionsSource = "import * as React from 'react';\nimport {\n  Chat,\n  Conversation,\n  MessageGroup,\n  MessageList,\n  createTimeWindowGroupKey,\n} from '@mui/x-chat/headless';\nimport type { ChatConversation, ChatMessage } from '@mui/x-chat/headless';\n\nconst adapter = {\n  async sendMessage() {\n    return new ReadableStream();\n  },\n};\n\nconst conversation: ChatConversation = {\n  id: 'meeting',\n  title: 'Design sync',\n  subtitle: 'Grouped by speaker and time window',\n};\n\nconst captions: ChatMessage[] = [\n  {\n    id: 'caption-1',\n    conversationId: 'meeting',\n    role: 'assistant',\n    author: { id: 'sam', displayName: 'Sam' },\n    createdAt: '2026-05-03T09:00:00.000Z',\n    parts: [{ type: 'text', text: 'Let us start with the mobile layout updates.' }],\n  },\n  {\n    id: 'caption-2',\n    conversationId: 'meeting',\n    role: 'assistant',\n    author: { id: 'sam', displayName: 'Sam' },\n    createdAt: '2026-05-03T09:03:00.000Z',\n    parts: [{ type: 'text', text: 'The new composer spacing feels much better.' }],\n  },\n];\n\nexport default function App() {\n  const groupKey = React.useMemo(() => createTimeWindowGroupKey(5 * 60_000), []);\n\n  return (\n    <Chat.Root\n      adapter={adapter}\n      initialConversations={[conversation]}\n      initialActiveConversationId={conversation.id}\n      initialMessages={captions}\n    >\n      <Conversation.Root style={{ background: '#121113', color: '#ffffff' }}>\n        <MessageList.Root\n          renderItem={({ id, index }) => (\n            <MessageGroup key={id} groupKey={groupKey} index={index} messageId={id} />\n          )}\n        />\n      </Conversation.Root>\n    </Chat.Root>\n  );\n}\n";

